import boto3
import json

dynamodb = boto3.resource('dynamodb')
table_name = 'user_data'

def lambda_handler(event, context):
    try:
        user_id = event['pathParameters']['id']
        table = dynamodb.Table(table_name)
        
        response = table.get_item(Key={'id': user_id})
        item = response['Item']
        
        return {
            'statusCode': 200,
            'headers': {
                'Access-Control-Allow-Origin': '*',
                'Content-Type': 'application/json'
            },
            'body': json.dumps(item)
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({'error': str(e)})
        }

def cors_config(event):
    return {
        'statusCode': 200,
        'headers': {
            'Content-Type': 'application/json',
            'Access-Control-Allow-Headers': '*',
            'Access-Control-Allow-Origin': '*',
            'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE'
        }
    }

def test(event):
    return cors_config(event)

def proxy(event, context):
    user_id = event['path']
    event = {
        "pathParameters": {"id": user_id}
    }
    
    response = lambda_handler(event, context)
    
    if 'error' in json.loads(response['body']):
        response['statusCode'] = 500
        return cors_config({"method": event['request']['method'], "path": event['request']['path'], "headers": event['request']['headers']})
    else:
        return response

from awsgi import response

def application(environ, start_response):
    if environ.get('HTTP_X_AMZ_LAMBDA_FUNCTION_NAME') == 'user_data_lambda':
        if environ['REQUEST_METHOD'] == 'OPTIONS':
            return cors_config({"method": "GET", "path": "/"})
        
        path_params = environ["path_info"].split("/")
        user_id = path_params[1]
        
        event = {
            "pathParameters": {"id": user_id}
        }
        
        response_body = lambda_handler(event, None)['body']
    else:
        start_response('404 Not Found', [('Content-type', 'text/plain')])
        return [b"Path not found"]
    
    status = response['statusCode']
    headers = [
        ("Content-Type", "application/json"),
        ("Access-Control-Allow-Origin", "*")
    ]
    
    if status == 200:
        return [
            b'',
            bytes(json.dumps(json.loads(response_body)), 'utf-8')
        ] + headers
    else:
        start_response(str(status), [('Content-type', 'text/plain')])
        return [b""] + headers

if __name__ == "__main__":
    from awsgi import App
    app = App(application)
